SELECT t.TRANSFER_ID, t.PLANT_CD, t.TRANSFER_NO, t.TRANSFER_STATUS, t.FROM_LOCATION_ID, t.TO_LOCATION_ID, t.TRANSFER_REASON, t.REG_USER_ID, t.REG_DTM, t.UPD_USER_ID, t.UPD_DTM, p.PLANT_NM, c.COM_NM AS TRANSFER_STATUS_NM, lf.LOCATION_CD AS FROM_LOCATION_CD, lt.LOCATION_CD AS TO_LOCATION_CD FROM MCS_TRANSFER_ORDER t INNER JOIN MST_PLANT p ON t.PLANT_CD = p.PLANT_CD INNER JOIN MCS_LOCATION lf ON t.FROM_LOCATION_ID = lf.LOCATION_ID INNER JOIN MCS_LOCATION lt ON t.TO_LOCATION_ID = lt.LOCATION_ID LEFT JOIN COM_CODE c ON c.GRP_CD = 'MCS_TF_STATUS' AND t.TRANSFER_STATUS = c.COM_CD
AND t.PLANT_CD = #{plantCd} AND t.TRANSFER_STATUS = #{transferStatus} AND t.TRANSFER_NO LIKE CONCAT('%', #{transferNo}, '%')
ORDER BY t.REG_DTM DESC, t.TRANSFER_NO DESC LIMIT #{size} OFFSET #{offset}

SELECT COUNT(*)
FROM MCS_TRANSFER_ORDER t

    AND t.PLANT_CD = #{plantCd}
    AND t.TRANSFER_STATUS = #{transferStatus}
    AND t.TRANSFER_NO LIKE CONCAT('%', #{transferNo}, '%')

